var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이 커다란 게... 네 친구라고?","JPN":"この大きいのが……君の友だち？","ENG":"That big thing... that's your friend?","TWN":"這麼大的東西……是你的朋友？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응. 이름은 기억 안 나지만.","JPN":"うん。名前は覚えてないけど。","ENG":"Yeah. I don't remember its name, though.","TWN":"嗯，但名字我想不起來了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"움직이지 않는데... 괜찮은 건가?","JPN":"動かないけど……大丈夫なの？","ENG":"It's not moving... is it all right?","TWN":"它不會動……沒關係嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"알 수 있어. 그냥 잠들어 있는 거 뿐이야.","JPN":"分かるんだ。今はただ眠ってるだけ。","ENG":"I can tell. It's just asleep.","TWN":"它知道，只是睡著了而已。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"근데, 깨어나기 싫은가 봐요.","JPN":"でも、起きたくないみたい。","ENG":"But... I guess it doesn't want to wake up.","TWN":"不過它好像不想醒來。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"깨어나기 싫은 거라고?","JPN":"起きたくない？","ENG":"It doesn't want to wake up?","TWN":"不想醒來？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"낙원은 모두의 소망을 이뤄주는 곳.","JPN":"楽園はみんなの願いを叶えてくれる場所。","ENG":"The Promised Land is a place that grants everyone's wishes.","TWN":"樂園是實現每個人願望的地方。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"누군가에겐 휴식이 가장 큰 소망일 수도 있는 법이지.","JPN":"誰かには休むことが最も大きな願いなのかもしれないわ。","ENG":"For some people, rest might be their greatest wish.","TWN":"對某些人來說，最大的願望可能是休息呢。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그럼, 클라라의 친구는 원하던 잠을 낙원에서 실컷 자고 있는 거구나.","JPN":"じゃあ、クララの友だちは楽園で思う存分眠っているわけか。","ENG":"Then Clara's friend must be getting all the sleep it ever wanted here in the Promised Land.","TWN":"所以克拉拉的朋友就在樂園裡盡情睡覺啊。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"깨워서 같이 놀고 싶지는 않아?","JPN":"起こして一緒に遊びたいとは思わないの？","ENG":"Don't you want to wake it up and play together?","TWN":"你不想叫醒它一起玩嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"괜찮아요. 노는 건 둘 다 즐거워야 하는걸.","JPN":"大丈夫。遊ぶなら二人とも楽しくなくちゃ。","ENG":"It's all right. Playing should be fun for both of us.","TWN":"沒關係，玩樂要雙方都快樂才有意義。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"지금도 전부 다 듣고 있을 테니까. 나중에 불러도 돼.","JPN":"今も全部聞いているはずだから。後で呼んでもいいの。","ENG":"It can hear everything even now. I can call it later.","TWN":"它現在也都聽得到，以後再叫它就好。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"나하고 친구, 모두가 원할 때.","JPN":"クララと友だち、二人とも遊びたい時にね。","ENG":"When both my friend and I want to.","TWN":"等到我和朋友都想這麼做的時候。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그럼.","JPN":"じゃあ。","ENG":"Then.","TWN":"好啊。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"친구가 깨어날 때까지는 나랑 같이 놀까?","JPN":"友だちが起きるまで、私と遊ぶ？","ENG":"Until your friend wakes up, want to play with me?","TWN":"朋友醒來前，我先和你一起玩吧？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"그래도 돼?","JPN":"いいの？","ENG":"Would that be all right?","TWN":"可以嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"너만 괜찮다면.","JPN":"君がよければ。","ENG":"If you're all right with it.","TWN":"只要你可以。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"...응.","JPN":"……うん。","ENG":"...Okay.","TWN":"……嗯。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"그치만, 떠나고 싶으면 말해도 돼요.","JPN":"でも、帰りたくなったらそう言って。","ENG":"But if you ever want to leave, you can say so.","TWN":"但如果你想離開，可以告訴我。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"떠나고 싶으면...?","JPN":"帰りたくなったら……？","ENG":"If I want to leave...?","TWN":"想離開……？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"별로, 그러고 싶어질 일은 없을 것 같긴 한데...","JPN":"別に、そうなることはないと思うけど……","ENG":"I don't think I'll feel that way...","TWN":"我應該不會有想離開的理由……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"약속 때문에 떠나고 싶어도 떠나지 못하는 건, 슬픈 일이니까.","JPN":"約束のせいで帰りたくても帰れないのは、悲しいことだから。","ENG":"Because wanting to leave but being unable to because of a promise is sad.","TWN":"如果因為約定讓你想離開卻走不了，也是件很悲傷的事。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래.","JPN":"分かった。","ENG":"Okay.","TWN":"是啊。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"같이 놀자. 우리 중 누군가 떠나고 싶을 때까지.","JPN":"一緒に遊ぼう。私たちのうちの誰かが帰りたくなるまで。","ENG":"Let's play together. Until one of us wants to leave.","TWN":"我們一起玩到有人想離開吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그때까지는 편히 쉬고 있어.","JPN":"だから、それまではゆっくり休んでて。","ENG":"Until then, rest easy.","TWN":"在那之前就好好休息。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"클라라의 친구.","JPN":"クララの友だち。","ENG":"Clara's friend.","TWN":"克拉拉的朋友。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아까부터 말이 없구나. 에클레시아.","JPN":"さっきから一言も話さないね、エクレシア。","ENG":"You've been quiet for a while, Ecclesia.","TWN":"你從剛才就沒說話呢，艾可露西亞。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"혹시, 내 요리가 맛이 없어서 그러니?","JPN":"もしかして、僕の料理がまずいのかい？","ENG":"Is it because my cooking isn't your taste?","TWN":"是不是覺得我的料理不好吃？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"예?!","JPN":"えっ！？","ENG":"Huh?!","TWN":"啊？！"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아뇨, 그럴 리가요! 아버지의 감자 요리가 세상에서 제일로 맛있사옵니다!","JPN":"いいえ、まさか！　お父様のポテト料理が世界で一番美味しいです！","ENG":"No, of course not! Father's potato dish is the most delicious thing in the world!","TWN":"不，怎麼可能！父親的馬鈴薯料理是世界上最好吃的！"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};